// ❌ BAD - no error handling leaves the account debited but not credited on failure
UPDATE BankAccounts SET Balance = Balance - 500 WHERE AccountId = 101;
UPDATE BankAccounts SET Balance = Balance + 500 WHERE AccountId = 202;

// ✅ GOOD - atomic bank transfer with full error handling
SET XACT_ABORT ON;
BEGIN TRY
    BEGIN TRANSACTION;
    UPDATE BankAccounts SET Balance = Balance - 500 WHERE AccountId = 101;
    UPDATE BankAccounts SET Balance = Balance + 500 WHERE AccountId = 202;
    IF (SELECT Balance FROM BankAccounts WHERE AccountId = 101) < 0
        THROW 50001, 'Insufficient funds', 1;
    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
    THROW;
END CATCH;

// ❌ BAD - NOLOCK hint risks dirty reads and missing or duplicate rows during page splits
SELECT * FROM Orders WITH (NOLOCK) WHERE CustomerId = 42;

// ✅ GOOD - enable RCSI at database level; readers get last committed version with no blocking
ALTER DATABASE ShopDb
    SET READ_COMMITTED_SNAPSHOT ON WITH ROLLBACK IMMEDIATE;

-- Ordinary queries now use versioning instead of shared locks
SELECT OrderId, Total FROM Orders WHERE CustomerId = 42;

-- Use Snapshot when the whole transaction needs a consistent point-in-time view
SET TRANSACTION ISOLATION LEVEL SNAPSHOT;
BEGIN TRANSACTION;
    SELECT Balance FROM BankAccounts WHERE AccountId = 101;
    SELECT Balance FROM BankAccounts WHERE AccountId = 202;
COMMIT;

// ❌ BAD - Session A locks Orders then Customers; Session B locks Customers then Orders - circular wait
-- Session A: BEGIN TRAN; UPDATE Orders ... then UPDATE Customers ...
-- Session B: BEGIN TRAN; UPDATE Customers ... then UPDATE Orders ...
-- Each waits for the other -> error 1205 on the victim

// ✅ GOOD - both sessions access tables in the same order to break the cycle
BEGIN TRAN;
    UPDATE Customers SET CreditLimit = 2000 WHERE CustomerId = 42;
    UPDATE Orders SET Status = 'Shipped' WHERE OrderId = 501;
COMMIT;

-- Read deadlock graphs from the system_health Extended Events session
SELECT xdr.value('@timestamp', 'datetime2') AS DeadlockTime,
       xdr.query('.') AS DeadlockGraph
FROM (SELECT CAST(target_data AS XML) AS TargetData
      FROM sys.dm_xe_session_targets t
      JOIN sys.dm_xe_sessions s ON t.event_session_address = s.address
      WHERE s.name = 'system_health' AND t.target_name = 'ring_buffer') AS Data
CROSS APPLY TargetData.nodes('//RingBufferTarget/event[@name="xml_deadlock_report"]') AS XEventData(xdr)
ORDER BY DeadlockTime DESC;

// ❌ BAD - 3NF violation: DepartmentName depends on DepartmentId, not on EmployeeId
CREATE TABLE Employees (
    EmployeeId     INT PRIMARY KEY,
    Name           NVARCHAR(100),
    DepartmentId   INT,
    DepartmentName NVARCHAR(100)  -- transitive dependency - remove this column
);

// ✅ GOOD - 3NF: DepartmentName lives in its own table
CREATE TABLE Departments (
    DepartmentId   INT PRIMARY KEY,
    DepartmentName NVARCHAR(100) NOT NULL
);
CREATE TABLE Employees (
    EmployeeId   INT PRIMARY KEY,
    Name         NVARCHAR(100) NOT NULL,
    DepartmentId INT NOT NULL REFERENCES Departments(DepartmentId)
);

-- Denormalized read-optimized reporting table (deliberate, documented decision)
CREATE TABLE EmployeeSalesReport (
    EmployeeId     INT,
    EmployeeName   NVARCHAR(100),
    DepartmentName NVARCHAR(100),  -- redundant but avoids join in every report
    TotalSales     DECIMAL(18,2)
);

// ❌ BAD - FK column not indexed; parent DELETE causes a full child table scan
CREATE TABLE Orders (
    OrderId    INT IDENTITY PRIMARY KEY,
    CustomerId INT NOT NULL REFERENCES Customers(CustomerId)
    -- no index on CustomerId - every parent delete scans this entire table
);

// ✅ GOOD - FK column indexed; named constraints for readable error messages
CREATE TABLE Orders (
    OrderId    INT IDENTITY CONSTRAINT PK_Orders PRIMARY KEY,
    CustomerId INT NOT NULL CONSTRAINT FK_Orders_Customers
                   REFERENCES Customers(CustomerId)
                   ON DELETE RESTRICT
                   ON UPDATE CASCADE
);
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId ON Orders (CustomerId);

-- Unique key on Email: enforces uniqueness, one NULL allowed
ALTER TABLE Customers
    ADD CONSTRAINT UQ_Customers_Email UNIQUE (Email);

// ❌ BAD - GUID clustered key causes random inserts and page splits
CREATE TABLE Shipments (
    ShipmentId UNIQUEIDENTIFIER DEFAULT NEWID() PRIMARY KEY,  -- random, fragments badly
    CustomerId INT,
    ShippedAt  DATETIME2
);

// ✅ GOOD - sequential IDENTITY key always appends to the end
CREATE TABLE Shipments (
    ShipmentId BIGINT    IDENTITY CONSTRAINT PK_Shipments PRIMARY KEY,
    CustomerId INT       NOT NULL,
    ShippedAt  DATETIME2 NOT NULL DEFAULT SYSUTCDATETIME()
);

-- Check fragmentation on the Shipments table
SELECT i.name AS IndexName,
       ips.avg_fragmentation_in_percent,
       ips.page_count
FROM sys.dm_db_index_physical_stats(DB_ID(), OBJECT_ID('Shipments'), NULL, NULL, 'LIMITED') ips
JOIN sys.indexes i ON ips.object_id = i.object_id AND ips.index_id = i.index_id
WHERE ips.avg_fragmentation_in_percent > 5;

-- Rebuild the clustered index online to remove fragmentation
ALTER INDEX PK_Shipments ON Shipments REBUILD WITH (ONLINE = ON);

// ❌ BAD - email as clustered PK: can change, wide, leaks into every FK column
CREATE TABLE Customers (Email NVARCHAR(256) PRIMARY KEY, Name NVARCHAR(100));

// ✅ GOOD - surrogate PK + separate unique constraint for natural key
CREATE TABLE Customers (
    CustomerId  BIGINT        IDENTITY CONSTRAINT PK_Customers PRIMARY KEY,
    Email       NVARCHAR(256) NOT NULL  CONSTRAINT UQ_Customers_Email UNIQUE,
    Name        NVARCHAR(200) NOT NULL,
    TenantId    INT           NOT NULL,
    CreatedAt   DATETIME2     NOT NULL  DEFAULT SYSUTCDATETIME(),
    ModifiedAt  DATETIME2     NOT NULL  DEFAULT SYSUTCDATETIME()
);
CREATE INDEX IX_Customers_TenantId ON Customers (TenantId);

-- Date-partitioned Orders for fast archiving via partition switch
CREATE PARTITION FUNCTION pf_OrderDate (DATE)
    AS RANGE RIGHT FOR VALUES ('2022-01-01','2023-01-01','2024-01-01','2025-01-01');
CREATE PARTITION SCHEME ps_OrderDate
    AS PARTITION pf_OrderDate ALL TO ([PRIMARY]);
CREATE TABLE Orders (
    OrderId   BIGINT IDENTITY,
    OrderDate DATE NOT NULL,
    Total     DECIMAL(18,2)
) ON ps_OrderDate(OrderDate);

// ❌ BAD - unnamed constraints produce unreadable error messages like 'UQ__Users__ABC123'
CREATE TABLE Users (
    UserId   INT           IDENTITY PRIMARY KEY,
    Email    NVARCHAR(256) NOT NULL UNIQUE,
    Username NVARCHAR(100) NOT NULL UNIQUE
);

// ✅ GOOD - named constraints with explicit index types
CREATE TABLE Users (
    UserId   INT           IDENTITY
                          CONSTRAINT PK_Users PRIMARY KEY CLUSTERED,
    Email    NVARCHAR(256) NOT NULL
                          CONSTRAINT UQ_Users_Email UNIQUE NONCLUSTERED,
    Username NVARCHAR(100) NOT NULL
                          CONSTRAINT UQ_Users_Username UNIQUE NONCLUSTERED
);

-- Test NULL behavior in a unique column
INSERT INTO Users (Email, Username) VALUES (NULL, 'alice');  -- succeeds (first NULL)
INSERT INTO Users (Email, Username) VALUES (NULL, 'bob');    -- fails  (second NULL = duplicate)
